import { BallEngine, deriveScore, RawCollisionEvent } from "./physics/ball-engine/ball-engine";
import { makeCannonBall, StaticBall } from "./ball";
import { MovingCannon as Cannon } from "./cannon";
import { CollisionHandler, DefaultCollisionHandler } from "./physics/ball-engine/collision-handler";
import { Observable } from "./observable";
import { COMBO_HIT_THRESHOLD, ORACLE_BONUS_COST } from "./constants";
import { WallSide } from "./physics/collision/ball-wall-collision-solver";
import { BallState } from "./physics/collision/fixed-points";

/**
 * Describes what was hit during a collision.
 * - `wall`: the live ball bounced off a wall.
 * - `ball`: the live ball struck a static ball.
 */
export type CollisionEventObstacle =
  | { type: 'wall'; wall: WallSide }
  | { type: 'ball'; ball: StaticBall; points: number; comboHit: boolean };

/**
 * A single collision event reported by {@link GameHandler.update}.
 *
 * Contains the full state of the live ball at the moment of impact, plus a
 * typed description of the obstacle that was hit. This is intentionally rich
 * so that visual effects (particles, floating labels) can be implemented
 * without needing to re-query the physics state.
 */
export interface CollisionEvent {
  /** Full kinematic state of the live ball at the moment of collision. */
  ball: BallState;
  obstacle: CollisionEventObstacle;
}

export class GameHandler {
  static readonly PAUSED = 1;
  static readonly RUNNING = 2;
  static readonly GAMEOVER = 3;

  observable = new Observable<{
    beginStep: [];
    endStep: [collisions: CollisionEvent[]];
    gameover: [number];
  }>();

  #state = GameHandler.PAUSED;

  #timeCorrection = 0;
  #lastFrameTime?: number;
  #animationFrameId?: number;

  highscore = 0;
  score = 0;
  lives = 0;
  oracleActive = false;
  enableComboHitPoints = true;

  #cannon: Cannon;
  #ballEngine: BallEngine;

  #snapshot = { score: 0 };

  /** Tracks total ball-collision hits in the current turn for combo bonus calculation. */
  #hitCounter = 0;

  constructor({cannon, ballEngine}: {cannon: Cannon; ballEngine: BallEngine}) {
    this.#cannon = cannon;
    this.#ballEngine = ballEngine;
  }

  get state() {
    return this.#state;
  }

  get currentBall() {
    return this.#ballEngine.currentBall;
  }

  get staticBalls() {
    return this.#ballEngine.staticBalls;
  }

  #update(frameTime: number, lastFrameTime: number): CollisionEvent[] {
    this.#cannon.update(frameTime, lastFrameTime);
    const updateState = this.#ballEngine.update(frameTime, lastFrameTime);

    const { hits, points } = deriveScore(updateState.collisions);
    this.score += points;

    let comboPointsAwardedNow = 0;

    if (this.enableComboHitPoints) {
      // Accumulate hits and award combo bonus points as soon as the threshold is crossed.
      const oldHits = this.#hitCounter;
      this.#hitCounter += hits;

      const oldComboPoints = Math.max(0, oldHits - COMBO_HIT_THRESHOLD);
      const newComboPoints = Math.max(0, this.#hitCounter - COMBO_HIT_THRESHOLD);
      comboPointsAwardedNow = newComboPoints - oldComboPoints;
      this.score += comboPointsAwardedNow;
    }

    this.highscore = Math.max(this.score, this.highscore);

    if (updateState.gameover) {
      this.#state = GameHandler.GAMEOVER;
      this.lives -= 1;
      this.observable.dispatchEvent('gameover', this.score);
    }

    return updateState.collisions.reverse()
      .map((c: RawCollisionEvent): CollisionEvent => {
        if (c.obstacle.type === 'wall') {
          return c as CollisionEvent;
        } else {
          return {
            ...c,
            obstacle: {
              ...c.obstacle,
              comboHit: this.enableComboHitPoints && comboPointsAwardedNow-- > 0,
            },
          };
        }
      })
      .reverse();
  }

  #step(frameTime: number, lastFrameTime: number) {
    this.#lastFrameTime = frameTime;

    if (this.#state === GameHandler.RUNNING) {
      this.observable.dispatchEvent('beginStep');

      const collisions = this.#update((frameTime - this.#timeCorrection) / 1000, (lastFrameTime - this.#timeCorrection) / 1000);

      this.observable.dispatchEvent('endStep', collisions);

      if (this.#state === GameHandler.RUNNING) {
        this.#animationFrameId = window.requestAnimationFrame(nextFrameTime => this.#step(nextFrameTime, frameTime));
      }
    }
  }

  #startOrResume(frameTime: number) {
    this.observable.dispatchEvent('beginStep');

    if (this.#lastFrameTime !== undefined) {
      this.#timeCorrection += frameTime - this.#lastFrameTime;
      this.#lastFrameTime = undefined;
    }

    // Causes the initial frame to be rendered.
    this.observable.dispatchEvent('endStep', []);

    this.#animationFrameId = window.requestAnimationFrame(nextFrameTime => this.#step(nextFrameTime, frameTime));
  }

  pause() {
    this.#state = GameHandler.PAUSED;

    if (this.#animationFrameId !== undefined) {
      window.cancelAnimationFrame(this.#animationFrameId);
      this.#animationFrameId = undefined;
    }
  }

  resume() {
    this.#state = GameHandler.RUNNING;
    window.requestAnimationFrame(nextFrameTime => this.#startOrResume(nextFrameTime));
  }

  reset() {
    this.#ballEngine.reset();
    this.#cannon.reset();
    this.score = 0;
    this.oracleActive = false;
    this.resume();
  }

  fire() {
    this.#takeSnapshot();

    // Reset per-turn combo tracking.
    this.#hitCounter = 0;

    this.score -= this.activeCollisionHandler.cost ?? 0;
    this.oracleActive = false;

    this.#ballEngine.fire(makeCannonBall({ angle: this.#cannon.getAngle() }));
  }

  #takeSnapshot() {
    this.#snapshot.score = this.score;
  }

  restoreSnapshot() {
    this.score = this.#snapshot.score;
    this.#ballEngine.restoreSnapshot();
  }

  canUseLife() {
    return this.lives > 0;
  }

  useLife() {
    if (!this.canUseLife()) {
      throw new Error('Out of lives.');
    }

    this.restoreSnapshot();
    this.oracleActive = false;

    this.resume();
  }

  /**
   * Returns true if the player can afford to enable the specified collision handler.
   */
  canEnableCollisionHandler(handler: CollisionHandler) {
    if (this.oracleActive) {
      return false;
    }
    return handler.cost === undefined || this.score >= handler.cost;
  }

  /**
   * Toggles a collision handler for the next ball.
   * If another collision handler was active, it will be replaced.
   */
  toggleCollisionHandler(handler: CollisionHandler) {
    if (this.#ballEngine.collisionHandler === handler) {
      this.#ballEngine.collisionHandler = DefaultCollisionHandler;
    } else {
      this.#ballEngine.collisionHandler = handler;
    }
  }

  /**
   * Applies the Oracle bonus.
   */
  applyOracleBonus() {
    if (this.score >= ORACLE_BONUS_COST) {
      this.score -= ORACLE_BONUS_COST;
      this.oracleActive = true;
      // Exclusivity: Disable Laser bonus if active
      this.#ballEngine.collisionHandler = DefaultCollisionHandler;
    }
  }

  /**
   * Returns the currently active collision handler.
   */
  get activeCollisionHandler(): CollisionHandler {
    return this.#ballEngine.collisionHandler;
  }
}
