HUD.register();
CssBoard.register();

function readStoredHighscore(): number {
  return parseInt(localStorage.getItem('highscore') || '0', 10);
}

const queryParams = new URLSearchParams(window.location.search);

function makeBallEngine(initialBallCounter?: number) {
  const engineName = queryParams.get('ball-engine') ?? 'math';
  switch (engineName) {
    case 'math':
      return new BallEngineMath({verbose: true, epsilon: 1e-10, initialBallCounter});
    case 'rk4':
      return new BallEngineRK4({verbose: true, initialBallCounter});
    case 'motion-equation-delta':
      return new BallEngineMotionEquationDelta({verbose: true, initialBallCounter});
    case 'motion-equation-absolute':
      return new BallEngineMotionEquationAbsolute({verbose: true, initialBallCounter});
    default:
      throw new Error(`Unknown ball engine: ${engineName}.`);
  }
}

const fpsStats = new Stats();
fpsStats.showPanel(0); // 0: fps, 1: ms
fpsStats.dom.style.removeProperty('top');
fpsStats.dom.style.position = 'fixed';
fpsStats.dom.style.left = '0px';
fpsStats.dom.style.bottom = '0px';
fpsStats.dom.style.display = 'none';
document.body.appendChild(fpsStats.dom);

const screenContainer = selectElement('#screenContainer');
const startScreen = selectElement('#start-screen');
const optionsScreen = selectElement('#optionsScreen');
const pauseScreen = selectElement('#pause-screen');
const gameoverScreen = selectElement('#gameover-screen');
const licenseScreen = selectElement('#licenseScreen');
const startWithThreeLivesButton = selectElement<HTMLInputElement>('#checkbox-start-three-lives');
const comboPointsCheckbox = selectElement<HTMLInputElement>('#checkbox-combo-hit-points');
const enableBonusesCheckbox = selectElement<HTMLInputElement>('#checkbox-enable-bonuses');
const showFramerateCheckbox = selectElement<HTMLInputElement>('#showFramerateCheckbox');
const soundCheckbox = selectElement<HTMLInputElement>('#soundCheckbox');
const vfxCheckbox = selectElement<HTMLInputElement>('#vfxCheckbox');
