import { CollisionHandler, CollisionResult, DefaultCollisionHandler } from "./collision-handler";
import { BallGeometry, computeExpandedRadius, MovingBall, StaticBall } from "../../ball";
import { WallSide } from "../collision/ball-wall-collision-solver";
import { BallState } from "../collision/fixed-points";
import { INITIAL_BALL_COUNTER } from "../../constants";

/**
 * Describes what was hit during a collision.
 * - `wall`: the live ball bounced off a wall.
 * - `ball`: the live ball struck a static ball.
 */
export type RawCollisionObstacle =
  | { type: 'wall'; wall: WallSide }
  | { type: 'ball'; ball: StaticBall; points: number; };

/**
 * A single collision event reported by {@link BallEngine.update}.
 *
 * Contains the full state of the live ball at the moment of impact, plus a
 * typed description of the obstacle that was hit.
 */
export interface RawCollisionEvent {
  /** Full kinematic state of the live ball at the moment of collision. */
  ball: BallState;
  obstacle: RawCollisionObstacle;
}

/**
 * The result of an update step.
 */
export interface UpdateResult {
  /** Whether the game is over. */
  gameover: boolean;
  /** All collision events (wall bounces and ball hits) that occurred in this update() call. */
  collisions: RawCollisionEvent[];
}

/**
 * Derives hits and points from a list of collision events.
 */
export function deriveScore(collisions: RawCollisionEvent[]): { hits: number; points: number } {
  let hits = 0;
  let points = 0;
  for (const c of collisions) {
    if (c.obstacle.type === 'ball') {
      hits += 1;
      points += c.obstacle.points;
    }
  }
  return { hits, points };
}

/**
 * A BallEngine is meant to implement the game physics.
 *
 * This involves computing the ball position according to the way it bounces
 * against the walls and the other balls.
 *
 * Because there are multiple ways to implement this, actual implementations must
 * inherit from this class and implement the {@link BallEngine.update | update}
 * and {@link BallEngine.internalFire | internalFire} methods.
 *
 * It additionally provides a snapshot capability to allow saving and restoring
 * the game in the state it was before a new ball is fired.
 */
export abstract class BallEngine {
  readonly verbose: boolean;
  staticBalls: Array<StaticBall>;
  abstract currentBall: BallGeometry | null;

  /** The collision handler that determines how ball-to-ball collisions are processed. */
  collisionHandler: CollisionHandler = DefaultCollisionHandler;

  #snapshot = new Array<[StaticBall, StaticBall]>();
  readonly #withSnapshots: boolean;

  initialBallCounter: number;

  constructor({ verbose = false, withSnapshots = true, initialBallCounter = INITIAL_BALL_COUNTER }: { verbose?: boolean, withSnapshots?: boolean, initialBallCounter?: number } = {}) {
    this.verbose = verbose;
    this.#withSnapshots = withSnapshots;
    this.initialBallCounter = initialBallCounter;
    this.staticBalls = [];
  }

  takeSnapshot(): void {
    if (this.#withSnapshots) {
      this.#snapshot = this.staticBalls.map<[StaticBall, StaticBall]>(b => [b, structuredClone(b)]);
    }
  }

  restoreSnapshot() {
    if (this.#withSnapshots) {
      this.staticBalls = this.#snapshot.map(([ball, snapshot]) => {
        ball.counter = snapshot.counter;
        ball.radius = snapshot.radius;
        ball.x = snapshot.x;
        ball.y = snapshot.y;
        return ball;
      });
    }
  }

  fire(ball: MovingBall) {
    this.takeSnapshot();

    if (this.verbose) {
      console.groupCollapsed('snapshot');
      console.log(ball);
      console.log(this.staticBalls);
      console.groupEnd();
    }

    this.internalFire(ball);
  }

  abstract internalFire(ball: MovingBall): void;

  abstract update(frameTime: number, lastFrameTime: number): UpdateResult;

  reset() {
    this.staticBalls = [];
    this.internalReset();
  }

  /**
   * Resets the engine by clearing the current ball.
   */
  internalReset() {
    this.currentBall = null;
    this.collisionHandler = DefaultCollisionHandler;
  }

  /**
   * Processes a ball-ball collision using the current collision handler.
   * Mutates the static ball's counter and removes it from staticBalls if destroyed.
   *
   * @returns The collision result and the points scored (0 or 1).
   */
  protected processBallCollision(staticBall: StaticBall): { result: CollisionResult; points: number } {
    const result = this.collisionHandler.onBallCollision(staticBall);

    staticBall.counter -= result.counterDecrement;
    if (staticBall.counter < 0) staticBall.counter = 0;

    let points = 0;
    if (staticBall.counter === 0) {
      this.staticBalls.splice(this.staticBalls.indexOf(staticBall), 1);
      if (result.scoreOnDestroy) {
        points = 1;
      }
    }

    return { result, points };
  }

  protected expandCurrentBall(currentBall: BallGeometry) {
    const expandedRadius = computeExpandedRadius(currentBall, this.staticBalls);
    this.staticBalls.push({
      counter: this.initialBallCounter,
      radius: expandedRadius,
      x: currentBall.x,
      y: currentBall.y,
    });
  }
}
