import { StaticBall } from "../core/ball";
import { DEFAULT_BALL_RADIUS } from "../core/constants";
import { CollisionEvent } from "../core/game-handler";
import { BallState } from "../core/physics/collision/fixed-points";

interface SpawnParticlesOptions {
  x: number;
  y: number;
  countRange: [number, number];
  radius: number;
  color: string;
  durationRange: [number, number];
  distanceRange: [number, number];
}

function randomRange([min, max]: [number, number]) {
  return min + Math.random() * (max - min);
}

const explosion_invariants = {
  color: 'white',
  countRange: [5, 8] satisfies [number, number],
  durationRange: [300, 500] satisfies [number, number],
  distanceRange: [5, 15] satisfies [number, number],
};

const collision_invariants = {
  color: 'black',
  countRange: [3, 5] satisfies [number, number],
  radius: DEFAULT_BALL_RADIUS / 2,
  durationRange: [200, 300] satisfies [number, number],
  distanceRange: [2, 8] satisfies [number, number],
};

function computeContactPoint(ball: BallState, staticBall: StaticBall) {
  const dx = ball.x - staticBall.x;
  const dy = ball.y - staticBall.y;
  const dist = Math.sqrt(dx * dx + dy * dy);
  const cx = staticBall.x + (dx / dist) * staticBall.radius;
  const cy = staticBall.y + (dy / dist) * staticBall.radius;
  return { cx, cy };
}

export class VfxManager {
  #container: HTMLElement;

  constructor(container: HTMLElement) {
    this.#container = container;
  }

  playCollisions(collisions: CollisionEvent[]) {
    for (const p of collisions) {
      if (p.obstacle.type === 'ball') {
        if (p.obstacle.ball.counter === 0) {
          this.#spawnParticles({
            x: p.obstacle.ball.x,
            y: p.obstacle.ball.y,
            radius: p.obstacle.ball.radius,
            ...explosion_invariants,
          });
        } else {
          const { cx, cy } = computeContactPoint(p.ball, p.obstacle.ball);
          this.#spawnParticles({
            x: cx,
            y: cy,
            ...collision_invariants,
          });
        }

        if (p.obstacle.comboHit) {
          const { cx, cy } = computeContactPoint(p.ball, p.obstacle.ball);
          this.#spawnPlusOne(cx, cy);
        }

        if (p.obstacle.points > 0) {
          this.#spawnPlusOne(p.obstacle.ball.x, p.obstacle.ball.y);
        }
      }
    }
  }

  #spawnParticles(
    { x, y, color, countRange, radius, durationRange, distanceRange }: SpawnParticlesOptions
  ) {
    const numParticles = randomRange(countRange);

    const startX = (x - radius) * 100;
    const startY = (y - radius) * 100;

    const sizePct = radius * 200;

    for (let i = 0; i < numParticles; i++) {
      const particle = document.createElement('div');
      particle.className = 'vfx-particle';
      particle.style.backgroundColor = color;

      const angle = Math.random() * Math.PI * 2;
      const distance = randomRange(distanceRange);

      const dx = Math.cos(angle) * distance;
      const dy = Math.sin(angle) * distance;

      particle.style.left = startX + '%';
      particle.style.bottom = startY + '%';
      particle.style.width = sizePct + '%';
      particle.style.height = sizePct + '%';

      this.#container.appendChild(particle);

      const duration = randomRange(durationRange);
      const animation = particle.animate(
        [
          { transform: 'translate(0, 0) scale(1)', opacity: 1 },
          { transform: `translate(${dx}vmin, ${-dy}vmin) scale(0)`, opacity: 0 }
        ],
        {
          duration,
          easing: 'cubic-bezier(0.25, 1, 0.5, 1)',
          fill: 'forwards'
        }
      );

      animation.onfinish = () => {
        particle.remove();
      };
    }
  }

  #spawnPlusOne(x: number, y: number) {
    const startX = x * 100;
    const startY = y * 100;

    const particle = document.createElement('div');
    particle.innerText = '+1';
    particle.className = 'vfx-particle';
    particle.style.backgroundColor = 'transparent';
    particle.style.left = startX + '%';
    particle.style.bottom = startY + '%';
    particle.style.color = 'white';
    particle.style.fontWeight = 'bold';
    particle.style.fontSize = '80%';
    particle.style.textShadow = '0 0 0.2em black';

    this.#container.appendChild(particle);
    const animation = particle.animate(
      [
        // -1ex to center the text horizontally
        { transform: 'translate(-1ex, 0)', opacity: 1 },
        { transform: 'translate(-1ex, -10vmin)', opacity: 0 }
      ],
      {
        duration: 1000,
        easing: 'cubic-bezier(0.25, 1, 0.5, 1)',
        fill: 'forwards'
      }
    );
    animation.onfinish = () => {
      particle.remove();
    };
  }
}
